class AtomicMarketplaceV3Composer:
    """Composer for creating transaction groups for AtomicMarketplaceV3 contract calls"""

    def __init__(self, client: "AtomicMarketplaceV3Client"):
        self.client = client
        self._composer = client.algorand.new_group()
        self._result_mappers: list[typing.Callable[[algokit_utils.ABIReturn | None], object] | None] = []

